class RealizedExpense extends DataClass implements Insertable<RealizedExpense> {
  final String id;
  final String packageId;
  final String planId;
  final String planLineId;

  /// `draft` | `proposed` | `accepted` | `published` | `rejected`
  final String status;
  final int amountMinor;
  final String currency;
  final DateTime paymentDate;
  final String payerParticipantId;

  /// `normal` | `reimbursement` | `advance` | `transfer`
  final String kind;
  final String? beneficiaryParticipantId;
  final String? description;

  /// Prior proposal when this row is a resubmit (pass 3+).
  final String? priorExpenseId;

  /// Frozen plan line title when the live line is removed from the plan.
  final String? planLineTitleSnapshot;

  /// JSON array of `{participantId, weight}` basis points at proposal time.
  final String? splitRatiosJson;

  /// Amount of this payment deferred to the next month on the payment-status chart.
  final int paymentChartCarryForwardMinor;
  final DateTime createdAt;
  final DateTime updatedAt;
  const RealizedExpense({
    required this.id,
    required this.packageId,
    required this.planId,
    required this.planLineId,
    required this.status,
    required this.amountMinor,
    required this.currency,
    required this.paymentDate,
    required this.payerParticipantId,
    required this.kind,
    this.beneficiaryParticipantId,
    this.description,
    this.priorExpenseId,
    this.planLineTitleSnapshot,
    this.splitRatiosJson,
    required this.paymentChartCarryForwardMinor,
    required this.createdAt,
    required this.updatedAt,
  });
  @override
  Map<String, Expression> toColumns(bool nullToAbsent) {
    final map = <String, Expression>{};
    map['id'] = Variable<String>(id);
    map['package_id'] = Variable<String>(packageId);
    map['plan_id'] = Variable<String>(planId);
    map['plan_line_id'] = Variable<String>(planLineId);
    map['status'] = Variable<String>(status);
    map['amount_minor'] = Variable<int>(amountMinor);
    map['currency'] = Variable<String>(currency);
    map['payment_date'] = Variable<DateTime>(paymentDate);
    map['payer_participant_id'] = Variable<String>(payerParticipantId);
    map['kind'] = Variable<String>(kind);
    if (!nullToAbsent || beneficiaryParticipantId != null) {
      map['beneficiary_participant_id'] = Variable<String>(
        beneficiaryParticipantId,
      );
    }
    if (!nullToAbsent || description != null) {
      map['description'] = Variable<String>(description);
    }
    if (!nullToAbsent || priorExpenseId != null) {
      map['prior_expense_id'] = Variable<String>(priorExpenseId);
    }
    if (!nullToAbsent || planLineTitleSnapshot != null) {
      map['plan_line_title_snapshot'] = Variable<String>(planLineTitleSnapshot);
    }
    if (!nullToAbsent || splitRatiosJson != null) {
      map['split_ratios_json'] = Variable<String>(splitRatiosJson);
